DO $$
DECLARE
  updated_count integer;
BEGIN
  UPDATE clubs AS c
  SET
    sec_name = i.sec_name,
    email = i.email,
    phone = i.phone,
    addr = i.addr,
    freq = i.freq,
    meeting_time = i.meeting_time,
    venue = i.venue,
    venue_tel = i.venue_tel,
    note = i.note
  FROM _020_club_directory_import AS i
  WHERE c.name = i.name
    AND c.zone = i.zone;

  GET DIAGNOSTICS updated_count = ROW_COUNT;

  IF updated_count <> 105 THEN
    RAISE EXCEPTION '020_seed_club_directory_from_excel expected to update 105 clubs, updated %', updated_count;
  END IF;
END $$;

COMMIT;
